/* Pick first active series and normalize fields */
const rows = $input.all().map(i => i.json);
if (!rows.length) throw new Error('No active series found in series sheet (active=TRUE).');
const s = rows[0];

// n8n Google Sheets node includes rowNumber in some modes; if not present, we can’t update next_part.
// In practice, read operation provides 'rowNumber'. If it doesn't, change Sheets node to return row numbers.
if (s.rowNumber === undefined) {
  // Still continue, but update step will fail.
  s.rowNumber = null;
}

const nextPart = Number(s.next_part);
if (!Number.isFinite(nextPart) || nextPart < 1) throw new Error('next_part must be a positive number in series sheet.');

return [{
  json: {
    series_rowNumber: s.rowNumber,
    series_id: String(s.series_id),
    series_title: String(s.series_title || ''),
    series_bible: String(s.series_bible || ''),
    part: nextPart,
    language: 'English',
    platforms: 'YouTube Shorts, Instagram Reels, Facebook Reels',
    length_sec: 30,
    audio_mode: 'tts'
  }
}];

/* Parse the model JSON */
const raw = $input.first().json;
const content = raw?.choices?.[0]?.message?.content;
if (!content) throw new Error('No message.content in OpenAI response');
let parsed;
try { parsed = JSON.parse(content); } catch (e) {
  const s = content.indexOf('{');
  const e2 = content.lastIndexOf('}');
  if (s === -1 || e2 === -1) throw new Error('Could not locate JSON in response: ' + content);
  parsed = JSON.parse(content.slice(s, e2 + 1));
}

// Validate top-level
for (const k of ['series_id','part','episode_title','short_video','audio','tomorrow_teaser']) {
  if (!(k in parsed)) throw new Error('Missing key: ' + k);
}

return [{ json: parsed }];

/*
Attach the audio binary as base64 so it can be stored in sheets (MVP).
Better: upload to Drive/S3 and store the URL.
*/
const item = $input.first();
const json = item.json;

// In n8n, binary will often be in item.binary.data
if (!item.binary || !item.binary.data) {
  throw new Error('No binary audio found. Check TTS node responseFormat=file.');
}

const b = item.binary.data;
// base64 already present in binary data structure; we want to store it as text
const base64 = b.data;

return [{
  json: {
    ...json,
    audio_file_base64: base64,
    created_at: new Date().toISOString()
  }
}];

/* Build update payload to increment next_part */
const seriesRows = $input.all().map(i => i.json);
if (!seriesRows.length) throw new Error('Could not re-find series row for update.');
const s = seriesRows[0];
if (s.rowNumber === undefined) throw new Error('rowNumber missing from Sheets read; enable returning row numbers in Sheets node.');

// We need the generated episode from previous nodes; use $items() to access earlier node output
const episode = $items('Attach Audio Base64')[0].json;

return [{
  json: {
    rowNumber: s.rowNumber,
    series_id: s.series_id,
    next_part: Number(episode.part) + 1
  }
}];
